}

func formatSlice[T any](slice []T) string {
	if slice == nil {
		return "nil"
	}
	output := ""
	for i, v := range slice {
		output += fmt.Sprintf("* %v", v)
		if i < len(slice)-1 {
			output += "\n"
		}
	}
	return output
}

